'use server';

import { cookies } from "next/headers";
import { revalidatePath } from "next/cache";

const API_URL = "https://sentinelle-api-backend-ntqku76mya-ew.a.run.app";

export async function addContactAction(formData: FormData) {
    const name = formData.get("name") as string;
    const email = formData.get("email") as string;
    const iban = formData.get("iban") as string;

    const cookieStore = await cookies();
    const token = cookieStore.get("auth-token");

    if (!token) {
        return { success: false, error: "Unauthorized" };
    }

    try {
        const payload: any = { name };
        if (email) payload.email = email;
        if (iban) payload.iban = iban;

        const res = await fetch(`${API_URL}/contacts/`, {
            method: "POST",
            headers: {
                "Authorization": `Bearer ${token.value}`,
                "Content-Type": "application/json"
            },
            body: JSON.stringify(payload)
        });

        if (!res.ok) {
            const error = await res.json();
            return { success: false, error: error.detail || "Failed to add contact" };
        }

        revalidatePath("/contacts");
        return { success: true };
    } catch (error) {
        return { success: false, error: "Network error" };
    }
}

export async function deleteContactAction(contactId: string) {
    const cookieStore = await cookies();
    const token = cookieStore.get("auth-token");

    if (!token) return { success: false, error: "Unauthorized" };

    try {
        const res = await fetch(`${API_URL}/contacts/${contactId}`, {
            method: "DELETE",
            headers: {
                "Authorization": `Bearer ${token.value}`
            }
        });

        if (!res.ok) {
            const txt = await res.text();
            console.error(`Delete failed: ${res.status} - ${txt}`);
            return { success: false, error: "Failed to delete" };
        }


        revalidatePath("/contacts");
        return { success: true };
    } catch (error) {
        return { success: false, error: "Network error" };
    }
}

export async function getContactsAction() {
    const cookieStore = await cookies();
    const token = cookieStore.get("auth-token");
    if (!token) return [];

    try {
        const res = await fetch(`${API_URL}/contacts/`, {
            method: "GET",
            headers: {
                "Authorization": `Bearer ${token.value}`,
                "Content-Type": "application/json"
            },
            cache: "no-store"
        });

        if (!res.ok) {
            return [];
        }

        return await res.json();
    } catch (error) {
        return [];
    }
}

"use client";

import { useTransactionSocket } from "@/hooks/use-transaction-socket";
import { TransactionStatus } from "@/types/transaction";
import { StatusBadge } from "@/components/ui/status-badge";
import { ArrowLeft, CheckCircle2, Circle, Loader2, ShieldAlert, ShieldCheck, AlertTriangle } from "lucide-react";
import Link from "next/link";
import { useParams, useSearchParams } from "next/navigation";
import { cn } from "@/lib/utils";
import { GlassCard } from "@/components/ui/glass-card";

export default function TrackingPage() {
    const params = useParams();
    const searchParams = useSearchParams();
    const id = params.id as string;
    const amount = searchParams.get("amount") || "120.00";
    const { status } = useTransactionSocket(id);

    const steps = [
        {
            id: "sent",
            label: "Virement initié",
            description: "Demande reçue par PayOn.",
            status: "completed",
            icon: CheckCircle2,
        },
        {
            id: "analyzing",
            label: "Analyse IA",
            description: "Détection de fraude en cours...",
            status:
                status === TransactionStatus.PENDING
                    ? "current"
                    : "completed",
            icon: ShieldCheck,
        },
        {
            id: "suspect",
            label: "Examen complémentaire",
            description: "Transaction en cours de revue manuelle.",
            status: status === TransactionStatus.SUSPECT ? "error" : (status === TransactionStatus.VALIDATED || status === TransactionStatus.REJECTED ? "completed" : "upcoming"),
            icon: AlertTriangle,
            hidden: status !== TransactionStatus.SUSPECT && status !== TransactionStatus.VALIDATED && status !== TransactionStatus.REJECTED // Only show if we hit this path
        },
        {
            id: "result",
            label: "Validation finale",
            description:
                status === TransactionStatus.REJECTED
                    ? "Bloqué par sécurité."
                    : "Fonds transférés.",
            status:
                status === TransactionStatus.PENDING || status === TransactionStatus.ANALYZING || status === TransactionStatus.SUSPECT
                    ? "upcoming"
                    : status === TransactionStatus.REJECTED
                        ? "error"
                        : "success",
            icon: status === TransactionStatus.REJECTED ? ShieldAlert : CheckCircle2,
        },
    ];

    return (
        <div className="space-y-6 max-w-xl mx-auto">
            <div className="flex items-center gap-4">
                <Link
                    href="/activity"
                    className="hidden md:inline-flex rounded-full p-2 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"
                >
                    <ArrowLeft className="h-6 w-6" />
                </Link>
                <div className="flex flex-col">
                    <h1 className="text-xl font-bold">Suivi de virement</h1>
                    <span className="text-xs text-muted-foreground">Réf: {id}</span>
                </div>
            </div>

            <GlassCard className="p-6">
                <div className="mb-8 flex items-center justify-between">
                    <div>
                        <p className="text-sm text-muted-foreground">Montant</p>
                        <p className="text-3xl font-bold">{amount} €</p>
                    </div>
                    <StatusBadge status={status} className="text-sm px-3 py-1 scale-110" />
                </div>

                {/* Vertical Stepper */}
                <div className="relative space-y-8 pl-4">
                    {/* Vertical Line */}
                    <div className="absolute left-[27px] top-2 bottom-4 w-0.5 bg-slate-200 dark:bg-slate-700" />

                    {steps.filter(s => !s.hidden).map((step, index) => {
                        const isCompleted = step.status === "completed" || step.status === "success";
                        const isCurrent = step.status === "current";
                        const isError = step.status === "error";

                        return (
                            <div key={step.id} className="relative flex items-start gap-4 animate-in slide-in-from-bottom-2 duration-500">
                                <div
                                    className={cn(
                                        "relative z-10 flex h-6 w-6 shrink-0 items-center justify-center rounded-full border-2 bg-background transition-colors",
                                        isCompleted && "border-indigo-600 bg-indigo-600 text-white",
                                        isCurrent && "border-indigo-600 animate-pulse",
                                        isError && "border-orange-500 bg-orange-500 text-white",
                                        !isCompleted && !isCurrent && !isError && "border-slate-300 dark:border-slate-600 bg-slate-50 dark:bg-slate-900"
                                    )}
                                >
                                    {isCurrent && <Loader2 className="h-3 w-3 animate-spin text-indigo-600" />}
                                    {isCompleted && <CheckCircle2 className="h-4 w-4" />}
                                    {isError && <AlertTriangle className="h-4 w-4" />}
                                    {!isCompleted && !isCurrent && !isError && <Circle className="h-3 w-3 text-muted-foreground" />}
                                </div>

                                <div className={cn("flex flex-col pt-0.5", (isCurrent || isCompleted || isError) ? "opacity-100" : "opacity-50")}>
                                    <span className="font-semibold text-sm">{step.label}</span>
                                    <span className="text-xs text-muted-foreground">{step.description}</span>

                                    {/* Info Block - No Actions */}
                                    {step.id === 'suspect' && isError && (
                                        <div className="mt-4 p-4 rounded-xl bg-orange-50 dark:bg-orange-900/20 border border-orange-200 dark:border-orange-800/50">
                                            <p className="text-sm font-medium text-orange-800 dark:text-orange-200 mb-1 flex items-center gap-2">
                                                <Loader2 className="h-4 w-4 animate-spin" />
                                                Analyse approfondie en cours
                                            </p>
                                            <p className="text-xs text-orange-700 dark:text-orange-300">
                                                Nos experts vérifient cette transaction. Aucune action n&apos;est requise de votre part.
                                            </p>
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </GlassCard>

            {status === TransactionStatus.VALIDATED && (
                <div className="rounded-xl bg-green-50 p-4 text-sm text-green-700 dark:bg-green-900/20 dark:text-green-400 border border-green-200 dark:border-green-800 animate-in zoom-in duration-300">
                    <div className="flex items-center gap-2 font-bold mb-1">
                        <CheckCircle2 className="h-4 w-4" />
                        Virement confirmé
                    </div>
                    Le destinataire recevra les fonds instantanéement.
                </div>
            )}
        </div>
    );
}

'use client';

import { GlassCard } from "@/components/ui/glass-card";
import { Plus, Search, User, Trash2, CheckCircle2, AlertCircle } from "lucide-react";
import Link from "next/link";
import { useState } from "react";
import { addContactAction, deleteContactAction } from "@/app/actions/contacts";
import { useRouter } from "next/navigation";
import { toast } from "react-hot-toast";

interface Contact {
    contact_id: string;
    name: string;
    email?: string;
    iban?: string;
    initials: string;
    is_internal: boolean;
}

interface Props {
    initialContacts: Contact[];
}

export function ContactList({ initialContacts }: Props) {
    const router = useRouter();
    const [contacts, setContacts] = useState<Contact[]>(initialContacts);
    const [searchTerm, setSearchTerm] = useState("");

    // Modal State
    const [isAddModalOpen, setIsAddModalOpen] = useState(false);
    const [newContactName, setNewContactName] = useState("");
    const [newContactEmail, setNewContactEmail] = useState("");
    const [modalStep, setModalStep] = useState(1); // 1: Input, 2: Success
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState("");

    const filteredContacts = contacts.filter(c =>
        c.name.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const handleAddContact = async () => {
        setError("");
        if (!newContactName.trim()) return;
        if (!newContactEmail.trim()) {
            setError("Veuillez saisir un email");
            return;
        }

        setIsSubmitting(true);
        const formData = new FormData();
        formData.append("name", newContactName);
        if (newContactEmail) formData.append("email", newContactEmail);

        const res = await addContactAction(formData);

        setIsSubmitting(false);

        if (res.success) {
            setModalStep(2);
            router.refresh();
            // Optimistic update handled by page refresh or could push to state
            setTimeout(() => {
                setIsAddModalOpen(false);
                setModalStep(1);
                setNewContactName("");
                setNewContactEmail("");
            }, 1500);
        } else {
            setError(res.error || "Erreur lors de l'ajout");
        }
    };

    // ... handleDelete (kept same)

    const handleDelete = async (e: React.MouseEvent, id: string) => {
        e.preventDefault(); // Prevent navigation
        if (!confirm("Voulez-vous supprimer ce contact ?")) return;

        const res = await deleteContactAction(id);
        if (res.success) {
            toast.success("Contact supprimé");
            router.refresh();
        } else {
            toast.error(res.error || "Erreur lors de la suppression");
            console.error(res.error);
        }
    };

    return (
        <div className="space-y-6">
            {/* Add Contact Modal Overlay */}
            {isAddModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm animate-in fade-in duration-200">
                    <div className="bg-white dark:bg-slate-900 w-full max-w-sm rounded-3xl p-6 shadow-2xl space-y-6 animate-in zoom-in-95 duration-200">
                        {modalStep === 1 ? (
                            <>
                                <div className="space-y-2 text-center">
                                    <h3 className="text-xl font-bold">Nouveau bénéficiaire</h3>
                                    <p className="text-sm text-muted-foreground">Ajouter un ami PayOn</p>
                                </div>

                                <div className="space-y-4">
                                    <div className="space-y-2">
                                        <label className="text-sm font-medium ml-1">Nom complet</label>
                                        <input
                                            autoFocus
                                            type="text"
                                            value={newContactName}
                                            onChange={e => setNewContactName(e.target.value)}
                                            className="w-full px-4 py-3 rounded-xl bg-slate-50 dark:bg-slate-800 border-none outline-none focus:ring-2 focus:ring-indigo-500 font-medium"
                                            placeholder="Ex: Marie Curie"
                                        />
                                    </div>

                                    {/* Email Only */}
                                    <div className="space-y-2">
                                        <label className="text-sm font-medium ml-1">Email <span className="text-xs text-muted-foreground">(Pour virement interne)</span></label>
                                        <input
                                            type="email"
                                            value={newContactEmail}
                                            onChange={e => setNewContactEmail(e.target.value)}
                                            className="w-full px-4 py-3 rounded-xl bg-slate-50 dark:bg-slate-800 border-none outline-none focus:ring-2 focus:ring-indigo-500"
                                            placeholder="marie.curie@email.com"
                                        />
                                    </div>

                                    {error && (
                                        <div className="flex items-center gap-2 text-xs text-red-600 bg-red-50 dark:bg-red-900/20 p-3 rounded-lg">
                                            <AlertCircle className="h-4 w-4" />
                                            {error}
                                        </div>
                                    )}
                                </div>

                                <div className="grid grid-cols-2 gap-3 pt-2">
                                    <button
                                        onClick={() => setIsAddModalOpen(false)}
                                        className="py-3 rounded-xl font-bold text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"
                                    >
                                        Annuler
                                    </button>
                                    <button
                                        onClick={handleAddContact}
                                        disabled={!newContactName.trim() || !newContactEmail || isSubmitting}
                                        className="py-3 rounded-xl font-bold bg-indigo-600 text-white shadow-lg shadow-indigo-500/20 hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all flex justify-center items-center"
                                    >
                                        {isSubmitting ? "Ajout..." : "Ajouter"}
                                    </button>
                                </div>
                            </>
                        ) : (
                            <div className="py-8 flex flex-col items-center gap-4 text-center">
                                <div className="h-16 w-16 rounded-full bg-green-100 text-green-600 flex items-center justify-center mb-2 animate-bounce">
                                    <CheckCircle2 className="h-8 w-8" />
                                </div>
                                <div>
                                    <h3 className="text-xl font-bold text-green-600">Contact ajouté !</h3>
                                    <p className="text-sm text-muted-foreground mt-1">{newContactName}</p>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            )}

            <div className="flex justify-between items-center bg-white dark:bg-slate-900 m-1 rounded-2xl shadow-sm p-1">
                {/* Search */}
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <input
                        type="text"
                        placeholder="Rechercher un contact..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-3 rounded-xl border-none bg-transparent outline-none transition-all"
                    />
                </div>
                <button
                    onClick={() => setIsAddModalOpen(true)}
                    className="p-3 mr-1 bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-500/20 hover:bg-indigo-700 transition-colors active:scale-95"
                >
                    <Plus className="h-5 w-5" />
                </button>
            </div>


            {/* Contacts Lists */}
            <div className="space-y-4">
                {filteredContacts.map(contact => (
                    <GlassCard key={contact.contact_id} className="flex items-center justify-between p-4 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors cursor-pointer group">
                        <div className="flex items-center gap-4">
                            <div className={`h-12 w-12 rounded-full flex items-center justify-center font-bold text-sm ${contact.is_internal ? "bg-indigo-100 text-indigo-600 dark:bg-indigo-900/40 dark:text-indigo-300" : "bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-400"}`}>
                                {contact.initials}
                            </div>
                            <div>
                                <div className="flex items-center gap-2">
                                    <p className="font-semibold">{contact.name}</p>
                                    {contact.is_internal && (
                                        <span className="text-[10px] bg-indigo-50 text-indigo-600 px-1.5 py-0.5 rounded font-bold border border-indigo-100 dark:bg-indigo-900/20 dark:border-indigo-800">
                                            APP
                                        </span>
                                    )}
                                </div>
                                <p className="text-xs text-muted-foreground truncate max-w-[180px]">
                                    {contact.email ? contact.email : contact.iban}
                                </p>
                            </div>
                        </div>
                        <div className="flex items-center gap-2">
                            <Link
                                href={`/transfer?to=${contact.email || contact.contact_id}`}
                                className="px-4 py-2 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 text-xs font-bold rounded-lg group-hover:bg-indigo-600 group-hover:text-white transition-colors"
                            >
                                Envoyer
                            </Link>

                            <button
                                onClick={(e) => handleDelete(e, contact.contact_id)}
                                className="p-2 text-slate-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"
                            >
                                <Trash2 className="h-4 w-4" />
                            </button>
                        </div>
                    </GlassCard>
                ))}

                {filteredContacts.length === 0 && (
                    <div className="text-center py-12 text-muted-foreground">
                        <User className="h-12 w-12 mx-auto mb-4 opacity-20" />
                        <p>Aucun contact trouvé</p>
                    </div>
                )}
            </div>
        </div>
    );
}

import { GlassCard } from "@/components/ui/glass-card";
import { ArrowLeft, Plus, Search, User, Trash2, CheckCircle2 } from "lucide-react";
import Link from "next/link";
import { cookies } from "next/headers";
import { ContactList } from "./contact-list";

const API_URL = "https://sentinelle-api-backend-ntqku76mya-ew.a.run.app";

// Server Component for fetching initial data
async function getContacts() {
    const cookieStore = await cookies();
    const token = cookieStore.get("auth-token");
    if (!token) return [];

    try {
        const res = await fetch(`${API_URL}/contacts/`, {
            headers: { "Authorization": `Bearer ${token.value}` },
            cache: "no-store"
        });
        if (!res.ok) return [];
        return await res.json();
    } catch (e) {
        return [];
    }
}

export default async function ContactsPage() {
    const contacts = await getContacts();

    return (
        <div className="max-w-2xl mx-auto space-y-6 pb-20 relative">
            {/* Header */}
            <div className="flex items-center gap-4">
                <Link href="/" className="rounded-full p-2 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors">
                    <ArrowLeft className="h-6 w-6" />
                </Link>
                <div className="flex-1">
                    <h1 className="text-2xl font-bold">Mes Contacts</h1>
                    <p className="text-sm text-muted-foreground">Gérez vos bénéficiaires</p>
                </div>
            </div>

            {/* Client Component handles Search, Modals and Interactions */}
            <ContactList initialContacts={contacts} />
        </div>
    );
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { mockTransactions } from '@/lib/mock-data';
import TransactionItem from '@/components/TransactionItem';
import Card from '@/components/ui/Card';
import Badge from '@/components/ui/Badge';
import { ClipboardDocumentListIcon } from '@heroicons/react/24/outline';

type Filter = 'all' | 'sent' | 'received';

export default function HistoryPage() {
  const router = useRouter();
  const [filter, setFilter] = useState<Filter>('all');
  
  const filteredTransactions = mockTransactions.filter((t) => {
    if (filter === 'all') return true;
    return t.type === filter;
  });
  
  const totalSent = mockTransactions
    .filter(t => t.type === 'sent' && t.status === 'validated')
    .reduce((sum, t) => sum + t.amount, 0);
  
  const totalReceived = mockTransactions
    .filter(t => t.type === 'received' && t.status === 'validated')
    .reduce((sum, t) => sum + t.amount, 0);
  
  return (
    <div className="min-h-screen pb-20">
      <main className="px-4 py-6 space-y-6">
        {/* Stats */}
        <div className="grid grid-cols-2 gap-4">
          <Card>
            <div className="text-sm text-gray-500 mb-1">Envoyé</div>
            <div className="text-2xl font-bold text-gray-900">{totalSent.toFixed(2)} €</div>
          </Card>
          <Card>
            <div className="text-sm text-gray-500 mb-1">Reçu</div>
            <div className="text-2xl font-bold text-green-600">{totalReceived.toFixed(2)} €</div>
          </Card>
        </div>
        
        {/* Filters */}
        <div className="flex gap-2">
          {(['all', 'sent', 'received'] as Filter[]).map((f) => (
            <button
              key={f}
              onClick={() => setFilter(f)}
              className={`px-4 py-2 rounded-full text-sm font-medium transition-colors ${
                filter === f
                  ? 'bg-gradient-to-r from-orange-500 to-blue-500 text-white'
                  : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
              }`}
            >
              {f === 'all' ? 'Tout' : f === 'sent' ? 'Envoyées' : 'Reçues'}
            </button>
          ))}
        </div>
        
        {/* Transactions List */}
        {filteredTransactions.length === 0 ? (
          <Card className="text-center py-12">
            <ClipboardDocumentListIcon className="w-16 h-16 mx-auto mb-2 text-gray-400" />
            <p className="text-gray-500">Aucune transaction</p>
          </Card>
        ) : (
          <div className="space-y-2">
            {filteredTransactions.map((transaction) => (
              <div
                key={transaction.id}
                onClick={() => router.push(`/history/${transaction.id}`)}
              >
                <TransactionItem transaction={transaction} />
              </div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
}

import Link from "next/link";
import { MoreHorizontal, Plus, Send, HandCoins } from "lucide-react";
import { TransactionItem } from "@/components/transactions/transaction-item";
import { ContactHomeItem } from "@/components/contacts/contact-home-item";
import { Transaction, TransactionStatus } from "@/types/transaction";
import { GlassCard } from "@/components/ui/glass-card";
import { ActionButton } from "@/components/ui/action-button";
import { PendingRequestsWidget } from "@/components/ui/pending-requests-widget";
import { cn } from "@/lib/utils";
import { cookies } from "next/headers";
import { redirect } from "next/navigation";

interface DashboardData {
  user: {
    display_name: string;
    email: string;
    risk_level: string;
    trust_score: number;
  };
  wallet: {
    wallet_id: string;
    balance: number;
    currency: string;
    kyc_status: string;
  } | null;
  recent_transactions: {
    transaction_id: string;
    amount: number;
    currency: string;
    transaction_type: string;
    direction: string;
    status: string;
    recipient_name: string;
    created_at: string;
  }[];
  contacts?: {
    name: string;
    email?: string;
    iban?: string;
    is_internal: boolean;
  }[];
}

const API_URL = "https://sentinelle-api-backend-ntqku76mya-ew.a.run.app";

async function getDashboardData(): Promise<DashboardData | null> {
  const cookieStore = await cookies();
  const token = cookieStore.get("auth-token");

  if (!token) return null;

  try {
    const res = await fetch(`${API_URL}/dashboard/`, {
      headers: {
        "Authorization": `Bearer ${token.value}`,
        "Content-Type": "application/json"
      },
      cache: "no-store",
    });

    if (!res.ok) {
      console.error(`Dashboard Fetch Error: ${res.status} ${res.statusText}`);
      const text = await res.text();
      console.error(`Response Body: ${text}`);
      if (res.status === 401) return null;
      return null;
    }

    return await res.json();
  } catch (error) {
    console.error("Dashboard network error details:", error);
    return null;
  }
}

export default async function Home() {
  const dashboardData = await getDashboardData();

  if (!dashboardData) {
    redirect("/login");
  }

  // Charger les demandes simulées depuis les cookies
  const cookieStore = await cookies();
  const requestsCookie = cookieStore.get("mock_requests");
  let mockRequests: {
    id: string;
    to: string;
    from: string;
    from_name: string;
    amount: number;
    comment: string;
    status: string;
    direction: "RECEIVED" | "SENT";
    date: string;
  }[] = [];
  if (requestsCookie) {
    try {
      mockRequests = JSON.parse(requestsCookie.value);
    } catch { }
  }

  const { user, wallet, recent_transactions, contacts } = dashboardData;

  const userEmail = user.email;

  // IMPORTANT: Re-évaluer la direction dynamiquement pour que les deux côtés voient la vue orientée correctement!
  mockRequests = mockRequests
    .filter((r) => r.to === userEmail || r.from === userEmail)
    .map((r) => {
        // Si la demande était adressée à l'utilisateur actuel, elle est REÇUE par eux
        const isReceived = r.to === userEmail;
        return {
            ...r,
            direction: isReceived ? "RECEIVED" : "SENT"
        };
    });

  const recentTransactions: Transaction[] = recent_transactions.map((t) => ({
    id: t.transaction_id,
    amount: t.amount,
    recipient: t.recipient_name || "Inconnu",
    status: t.status as TransactionStatus,
    date: t.created_at,
    direction: t.direction as 'INCOMING' | 'OUTGOING' // Explicitly map direction
  }));

  const resolvedRequests: Transaction[] = mockRequests.filter((r) => r.status !== "PENDING").map((r) => ({
    id: r.id,
    amount: r.amount,
    recipient: r.direction === "RECEIVED" ? (r.from_name || r.from || "Contact") : r.to,
    status: (r.status === "ACCEPTED" ? "VALIDATED" : "REJECTED") as TransactionStatus,  // Map to TransactionStatus
    date: r.date,
    direction: r.direction === "RECEIVED" ? "OUTGOING" : "INCOMING", // Si je reçois une demande et que je l'accepte, je transfère de l'argent (OUTGOING)
    comment: r.comment ? `Suite à demande : ${r.comment}` : "Suite à une demande"
  }));

  const allTransactions = [...recentTransactions, ...resolvedRequests].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const formatCurrency = (amount: number, currency: string) => {
    // Si la devise est PYC, ajouter simplement la string. Sinon, utiliser intl.
    if (currency === "PYC" || currency === "EUR") { // Traiter l'ancienne devise EUR pour la cohérence de l'affichage
      return new Intl.NumberFormat('fr-FR', { style: 'decimal', minimumFractionDigits: 2 }).format(amount) + " PYC";
    }
    return new Intl.NumberFormat('fr-FR', { style: 'currency', currency: currency }).format(amount);
  };

  // Helper pour le Badge de Niveau de Risque
  const getRiskBadgeColor = (level: string) => {
    switch (level) {
      case "LOW": return "bg-green-100 text-green-700 dark:bg-green-500/20 dark:text-green-400 border-green-200 dark:border-green-500/30";
      case "MEDIUM": return "bg-yellow-100 text-yellow-700 dark:bg-yellow-500/20 dark:text-yellow-400 border-yellow-200 dark:border-yellow-500/30";
      case "HIGH": return "bg-red-100 text-red-700 dark:bg-red-500/20 dark:text-red-400 border-red-200 dark:border-red-500/30";
      default: return "bg-slate-100 text-slate-700 dark:bg-slate-800 dark:text-slate-400";
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">

      {/* En-tête avec Bonjour & Indicateur de Confiance */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 px-1">
        <div>
          <div className="flex items-center gap-3 mb-1">
