import { ArrowLeft } from "lucide-react";
import Link from "next/link";
import { cookies } from "next/headers";
import { RequestForm } from "./request-form";

const API_URL = "https://sentinelle-api-backend-ntqku76mya-ew.a.run.app";

async function getContacts() {
    const cookieStore = await cookies();
    const token = cookieStore.get("auth-token");
    if (!token) {
        return { contacts: [], user: null };
    }

    try {
        const res = await fetch(`${API_URL}/contacts/`, {
            headers: { "Authorization": `Bearer ${token.value}` },
            cache: "no-store"
        });

        // Use dashboard to get full user info
        const dashRes = await fetch(`${API_URL}/dashboard/`, {
            headers: { "Authorization": `Bearer ${token.value}` },
            cache: "no-store"
        });

        const contacts = res.ok ? await res.json() : [];
        const dashData = dashRes.ok ? await dashRes.json() : null;
        const user = dashData?.user || null;
        
        return { contacts, user };
    } catch (e) {
        return { contacts: [], user: null };
    }
}

export default async function RequestPage() {
    const { contacts, user } = await getContacts();

    return (
        <div className="flex min-h-[80vh] flex-col">
            {/* Header */}
            <div className="flex items-center gap-4 mb-6">
                <Link href="/" className="rounded-full p-2 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors">
                    <ArrowLeft className="h-6 w-6" />
                </Link>
                <h1 className="text-xl font-bold">Demander de l'argent</h1>
            </div>

            <RequestForm 
                contacts={contacts} 
                currentUserEmail={user?.email} 
                currentUserName={[user?.first_name, user?.last_name].filter(Boolean).join(' ') || user?.email}
            />
        </div>
    );
}

"use client";

import { createRequestAction } from "@/app/actions/request";
import { getContactsAction } from "@/app/actions/contacts";
import { HandCoins, ShieldCheck } from "lucide-react";
import { useActionState, useState, useEffect } from "react";
import { useFormStatus } from "react-dom";
import { cn } from "@/lib/utils";
import { useSearchParams } from "next/navigation";
import { TransactionLoader } from "@/components/ui/transaction-loader";

interface Contact {
    contact_id: string;
    name: string;
    email?: string;
    iban?: string;
    initials: string;
    is_internal: boolean;
}

interface Props {
    contacts: Contact[];
    currentUserEmail?: string;
    currentUserName?: string;
}

function SubmitButton() {
    const { pending } = useFormStatus();

    return (
        <button
            type="submit"
            disabled={pending}
            className={cn(
                "group mt-8 flex w-full items-center justify-center gap-2 rounded-2xl bg-indigo-600 hover:bg-indigo-700 py-4 font-bold text-white shadow-xl shadow-indigo-500/20 transition-all active:scale-95 disabled:opacity-70 disabled:active:scale-100",
                pending && "cursor-not-allowed opacity-80"
            )}
        >
            {pending ? (
                <span className="animate-pulse">Demande en cours...</span>
            ) : (
                <>
                    <span>Demander les fonds</span>
                    <HandCoins className="h-4 w-4 transition-transform group-hover:scale-110" />
                </>
            )}
        </button>
    );
}

export function RequestForm({ contacts: initialContacts, currentUserEmail, currentUserName }: Props) {
    const searchParams = useSearchParams();
    const initialRecipient = searchParams.get("to") || "";

    const initialState = {
        success: false,
        message: "",
    };

    // @ts-ignore
    const [state, formAction] = useActionState(createRequestAction, initialState);

    const [contacts, setContacts] = useState<Contact[]>(initialContacts);
    const [amount, setAmount] = useState("");
    const [recipient, setRecipient] = useState(initialRecipient);
    const [isLoading, setIsLoading] = useState(false);
    const [errorDismissed, setErrorDismissed] = useState(false);

    useEffect(() => {
        const fetchContacts = async () => {
            if (contacts.length === 0) {
                setIsLoading(true);
                try {
                    const data = await getContactsAction();
                    if (data) setContacts(data);
                } catch (error) {
                    console.error("Failed to fetch contacts", error);
                } finally {
                    setIsLoading(false);
                }
            }
        };
        fetchContacts();
    }, [contacts.length]);

    const validContacts = contacts.filter(c => c.email || c.iban);

    useEffect(() => {
        if (initialRecipient && contacts.length > 0) {
            const matched = contacts.find(c => c.contact_id === initialRecipient || c.email === initialRecipient);
            if (matched) {
                setRecipient(matched.email || matched.iban || "");
            } else if (initialRecipient.includes("@") || initialRecipient.startsWith("FR")) {
                setRecipient(initialRecipient);
            }
        }
    }, [initialRecipient, contacts]);

    useEffect(() => {
        if (state?.message) {
            setErrorDismissed(false);
        }
    }, [state]);

    const handleContactClick = (contact: Contact) => {
        setRecipient(contact.email || contact.iban || "");
    };

    if (state?.message && !state.success && !errorDismissed) {
        return (
            <div className="flex flex-1 flex-col items-center justify-center p-6 text-center animate-in zoom-in-95 duration-300">
                <div className="mb-6 relative">
                    <div className="absolute inset-0 bg-red-500/10 blur-2xl rounded-full" />
                    <div className="relative h-20 w-20 bg-red-50 dark:bg-red-900/20 rounded-full flex items-center justify-center border-2 border-red-100 dark:border-red-900">
                        <ShieldCheck className="h-10 w-10 text-red-500" />
                    </div>
                </div>
                <h2 className="text-xl font-bold text-red-600 dark:text-red-500 mb-2">Refusé</h2>
                <p className="text-muted-foreground max-w-xs mb-8">{state.message}</p>
                <button
                    onClick={() => setErrorDismissed(true)}
                    className="w-full max-w-xs py-3 px-4 rounded-xl bg-slate-100 dark:bg-slate-800 text-foreground font-medium hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
                >
                    Modifier la demande
                </button>
            </div>
        );
    }

    return (
        <form action={formAction} className="relative flex flex-1 flex-col h-full">
            <TransactionLoader />
            <div className="space-y-4 pt-4">
                <label className="text-sm font-medium text-muted-foreground ml-1">À qui ?</label>
                {isLoading ? (
                    <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide opacity-50">
                        {[1, 2, 3].map(i => (
                            <div key={i} className="h-10 w-24 bg-slate-100 rounded-full animate-pulse" />
                        ))}
                    </div>
                ) : validContacts.length > 0 ? (
                    <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide">
                        {validContacts.map((c) => (
                            <div
                                key={c.contact_id}
                                onClick={() => handleContactClick(c)}
                                className={cn(
                                    "flex flex-shrink-0 items-center gap-2 rounded-full border bg-white p-1 pr-4 shadow-sm cursor-pointer transition-all dark:bg-slate-900 dark:border-slate-800",
                                    (recipient === c.email || recipient === c.iban)
                                        ? "border-indigo-600 ring-2 ring-indigo-100 dark:ring-indigo-900"
                                        : "border-slate-200 hover:border-indigo-300"
                                )}
                            >
                                <div className={cn(
                                    "h-8 w-8 rounded-full flex items-center justify-center text-xs font-bold",
                                    c.is_internal ? "bg-indigo-100 text-indigo-600" : "bg-slate-100 text-slate-600"
                                )}>
                                    {c.initials}
                                </div>
                                <span className="text-sm font-medium">{c.name}</span>
                            </div>
                        ))}
                    </div>
                ) : (
                    <p className="text-xs text-muted-foreground italic ml-1">Aucun contact enregistré.</p>
                )}

                <div className="relative">
                    <input type="hidden" name="knownContacts" value={contacts.map(c => c.email + "|" + c.iban).join(',')} />
                    <input type="hidden" name="fromUser" value={currentUserEmail || ""} />
                    <input type="hidden" name="fromUserName" value={currentUserName || currentUserEmail?.split('@')[0] || ""} />
                    <input
                        required
                        name="recipient"
                        type="text"
                        placeholder="Email ou ID utilisateur..."
                        value={recipient}
                        onChange={(e) => setRecipient(e.target.value)}
                        className="w-full rounded-xl border-0 bg-slate-100 px-4 py-4 text-base outline-none ring-1 ring-transparent focus:bg-white focus:ring-primary/20 transition-all dark:bg-slate-800 dark:focus:bg-slate-900 text-slate-900 dark:text-white placeholder:text-slate-400"
                    />
                </div>
            </div>

            <div className="space-y-2 mt-4">
                <label htmlFor="comment" className="text-sm font-medium text-muted-foreground ml-1">Motif (optionnel)</label>
                <textarea
                    name="comment"
                    id="comment"
                    rows={2}
                    placeholder="Pour le restaurant d'hier..."
                    className="w-full rounded-xl border-0 bg-slate-100 px-4 py-3 text-sm outline-none ring-1 ring-transparent focus:bg-white focus:ring-primary/20 transition-all dark:bg-slate-800 dark:focus:bg-slate-900 text-slate-900 dark:text-white placeholder:text-slate-400 resize-none"
                />
            </div>

            <div className="flex-1 flex flex-col items-center justify-center gap-4 min-h-[200px]">
                <label htmlFor="amount" className="text-sm font-medium text-muted-foreground uppercase tracking-widest">
                    Montant demandé
                </label>
                <div className="relative flex items-center justify-center w-full">
                    <input
                        required
                        name="amount"
                        id="amount"
                        type="text"
                        inputMode="decimal"
                        placeholder="0"
                        value={amount}
                        onChange={(e) => {
                            const val = e.target.value.replace(',', '.');
                            if (val === '' || /^\d*\.?\d{0,2}$/.test(val)) {
                                setAmount(val);
                            }
                        }}
                        className="w-full text-center bg-transparent text-6xl md:text-8xl font-black tracking-tighter outline-none placeholder:text-slate-100 dark:placeholder:text-slate-800 text-slate-900 dark:text-white transition-all scale-100 focus:scale-105"
                        style={{ maxWidth: '400px' }}
                    />
                    <span className="text-5xl font-medium text-slate-400 absolute right-[10%] top-6 pointer-events-none">PYC</span>
                </div>
            </div>

            <div className="mt-auto pb-4 space-y-4">
                {state?.message && !state.success && (
                    <div className="bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 p-3 rounded-xl flex items-center gap-2 text-sm font-medium animate-in fade-in slide-in-from-bottom-2 border border-red-100 dark:border-red-900">
                        <div className="h-5 w-5 rounded-full bg-red-100 dark:bg-red-900 flex items-center justify-center shrink-0 font-bold">!</div>
                        {state.message}
                    </div>
                )}
                <SubmitButton />
            </div>
        </form>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { mockContacts } from '@/lib/mock-data';
import Button from '@/components/ui/Button';
import Card from '@/components/ui/Card';
import Skeleton from '@/components/ui/Skeleton';
import { CheckCircleIcon, XCircleIcon } from '@heroicons/react/24/outline';

type Step = 'contact' | 'amount' | 'confirm' | 'processing';

export default function SendPage() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const contactParam = searchParams.get('contact');
  const [step, setStep] = useState<Step>(contactParam ? 'amount' : 'contact');
  const [selectedContact, setSelectedContact] = useState<string | null>(contactParam);
  const [amount, setAmount] = useState<string>('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [transactionStatus, setTransactionStatus] = useState<'validated' | 'verifying' | 'blocked' | null>(null);
  
  const contact = selectedContact ? mockContacts.find(c => c.id === selectedContact) : null;
  
  const handleContactSelect = (contactId: string) => {
    setSelectedContact(contactId);
    setStep('amount');
  };
  
  const handleAmountSubmit = () => {
    if (parseFloat(amount) > 0) {
      setStep('confirm');
    }
  };
  
  const handleConfirm = async () => {
    setIsProcessing(true);
    setStep('processing');
    
    // Simuler le traitement par l'IA
    await new Promise(resolve => setTimeout(resolve, 1500));
    
    // Simuler différents résultats (80% validé, 15% vérification, 5% bloqué)
    const random = Math.random();
    if (random < 0.8) {
      setTransactionStatus('validated');
    } else if (random < 0.95) {
      setTransactionStatus('verifying');
      router.push(`/verify?amount=${amount}&contact=${selectedContact}`);
      return;
    } else {
      setTransactionStatus('blocked');
    }
    
    setIsProcessing(false);
  };
  
  const handleFinish = () => {
    router.push('/');
  };
  
  return (
    <div className="min-h-screen pb-20">
      <main className="px-4 py-6">
        {/* Step Indicator */}
        <div className="flex items-center justify-center gap-2 mb-8">
          {['contact', 'amount', 'confirm'].map((s, i) => (
            <div key={s} className="flex items-center">
              <div
                  className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-semibold ${
                  step === s || (step === 'processing' && i < 3)
                    ? 'bg-gradient-to-r from-orange-500 to-blue-500 text-white'
                    : step !== 'contact' && ['amount', 'confirm'].indexOf(step) > i
                    ? 'bg-green-500 text-white'
                    : 'bg-gray-200 text-gray-500'
                }`}
              >
                {step !== 'contact' && ['amount', 'confirm'].indexOf(step) > i ? '✓' : i + 1}
              </div>
              {i < 2 && (
                <div
                  className={`w-12 h-1 ${
                    step !== 'contact' && ['amount', 'confirm'].indexOf(step) > i
                      ? 'bg-green-500'
                      : 'bg-gray-200'
                  }`}
                />
              )}
            </div>
          ))}
        </div>
        
        {/* Step 1: Select Contact */}
        {step === 'contact' && (
          <div className="space-y-4">
            <h2 className="text-lg font-semibold text-gray-900 mb-4">Sélectionner un contact</h2>
            
            {/* Favorites */}
            <div>
              <h3 className="text-sm font-medium text-gray-500 mb-2">Favoris</h3>
              <div className="space-y-2">
                {mockContacts
                  .filter(c => c.isFavorite)
                  .map((contact) => (
                    <Card
                      key={contact.id}
                      onClick={() => handleContactSelect(contact.id)}
                      className="flex items-center gap-3"
                    >
                      <div className="w-12 h-12 rounded-full bg-gradient-to-br from-orange-400 to-blue-400 flex items-center justify-center text-white font-semibold">
                        {contact.name.charAt(0)}
                      </div>
                      <div className="flex-1">
                        <div className="font-semibold text-gray-900">{contact.name}</div>
                      </div>
                      <span className="text-gray-400">→</span>
                    </Card>
                  ))}
              </div>
            </div>
            
            {/* All Contacts */}
            <div>
              <h3 className="text-sm font-medium text-gray-500 mb-2">Tous les contacts</h3>
              <div className="space-y-2">
                {mockContacts
                  .filter(c => !c.isFavorite)
                  .map((contact) => (
                    <Card
                      key={contact.id}
                      onClick={() => handleContactSelect(contact.id)}
                      className="flex items-center gap-3"
                    >
                      <div className="w-12 h-12 rounded-full bg-gradient-to-br from-orange-400 to-blue-400 flex items-center justify-center text-white font-semibold">
                        {contact.name.charAt(0)}
                      </div>
                      <div className="flex-1">
                        <div className="font-semibold text-gray-900">{contact.name}</div>
                      </div>
                      <span className="text-gray-400">→</span>
                    </Card>
                  ))}
              </div>
            </div>
          </div>
        )}
        
        {/* Step 2: Enter Amount */}
        {step === 'amount' && contact && (
          <div className="space-y-6">
            <div className="text-center">
              <div className="w-20 h-20 rounded-full bg-gradient-to-br from-orange-400 to-blue-400 flex items-center justify-center text-white text-2xl font-semibold mx-auto mb-4">
                {contact.name.charAt(0)}
              </div>
              <h2 className="text-xl font-semibold text-gray-900 mb-1">{contact.name}</h2>
            </div>
            
            <Card className="text-center py-8">
              <label className="block text-sm text-gray-500 mb-2">Montant</label>
              <div className="flex items-center justify-center gap-2">
                <input
                  type="number"
                  value={amount}
                  onChange={(e) => setAmount(e.target.value)}
                  placeholder="0.00"
                  className="text-4xl font-bold text-gray-900 text-center border-none outline-none w-full"
                  autoFocus
                />
                <span className="text-2xl text-gray-500">€</span>
              </div>
            </Card>
            
            <Button
              variant="primary"
              size="lg"
              className="w-full"
              onClick={handleAmountSubmit}
              disabled={!amount || parseFloat(amount) <= 0}
            >
              Continuer
            </Button>
          </div>
        )}
        
        {/* Step 3: Confirm */}
        {step === 'confirm' && contact && (
          <div className="space-y-6">
            <h2 className="text-lg font-semibold text-gray-900 text-center">Confirmer la transaction</h2>
            
            <Card className="space-y-4">
              <div className="flex items-center gap-3 pb-4 border-b border-gray-100">
                <div className="w-12 h-12 rounded-full bg-gradient-to-br from-orange-400 to-blue-400 flex items-center justify-center text-white font-semibold">
                  {contact.name.charAt(0)}
                </div>
                <div className="flex-1">
                  <div className="text-sm text-gray-500">Destinataire</div>
                  <div className="font-semibold text-gray-900">{contact.name}</div>
                </div>
              </div>
              
              <div>
                <div className="text-sm text-gray-500 mb-1">Montant</div>
                <div className="text-3xl font-bold text-gray-900">{parseFloat(amount).toFixed(2)} €</div>
              </div>
            </Card>
            
            <Button
              variant="primary"
              size="lg"
              className="w-full"
              onClick={handleConfirm}
            >
              Envoyer
            </Button>
          </div>
        )}
        
        {/* Step 4: Processing */}
        {step === 'processing' && (
          <div className="space-y-6 text-center py-12">
            <div className="w-20 h-20 mx-auto mb-4">
              <div className="w-full h-full border-4 border-orange-200 border-t-orange-500 rounded-full animate-spin" />
            </div>
            <h2 className="text-xl font-semibold text-gray-900">Traitement en cours...</h2>
            <p className="text-gray-500">Vérification de sécurité par IA</p>
          </div>
        )}
        
        {/* Transaction Result */}
        {transactionStatus === 'validated' && (
          <div className="space-y-6 text-center py-12">
            <div className="w-20 h-20 mx-auto mb-4 bg-green-100 rounded-full flex items-center justify-center">
              <CheckCircleIcon className="w-12 h-12 text-green-600" />
            </div>
            <h2 className="text-xl font-semibold text-gray-900">Transaction validée</h2>
            <p className="text-gray-500">
              {amount} € ont été envoyés à {contact?.name}
            </p>
            <Button
              variant="primary"
              size="lg"
              className="w-full"
              onClick={handleFinish}
            >
              Retour à l'accueil
            </Button>
          </div>
        )}
        
        {transactionStatus === 'blocked' && (
          <div className="space-y-6 text-center py-12">
            <div className="w-20 h-20 mx-auto mb-4 bg-red-100 rounded-full flex items-center justify-center">
              <XCircleIcon className="w-12 h-12 text-red-600" />
            </div>
            <h2 className="text-xl font-semibold text-gray-900">Transaction bloquée</h2>
            <p className="text-gray-500 mb-4">
              Cette transaction a été bloquée pour votre sécurité.
            </p>
            <Card className="text-left">
              <p className="text-sm text-gray-600">
                Si vous pensez qu'il s'agit d'une erreur, contactez notre support.
              </p>
            </Card>
            <Button
              variant="primary"
              size="lg"
              className="w-full"
              onClick={handleFinish}
            >
              Retour à l'accueil
            </Button>
          </div>
        )}
      </main>
    </div>
  );
}

"use client";

import { createTransferAction } from "@/app/actions";
import { getContactsAction } from "@/app/actions/contacts"; // Importation de la nouvelle action
import { Send, RefreshCw, ShieldCheck } from "lucide-react";
import { useActionState, useState, useEffect } from "react"; // Ajout de useActionState
import { useFormStatus } from "react-dom";
import { cn } from "@/lib/utils";
import { useSearchParams } from "next/navigation";
import { TransactionLoader } from "@/components/ui/transaction-loader";

interface Contact {
    contact_id: string;
    name: string;
    email?: string;
    iban?: string;
    initials: string;
    is_internal: boolean;
}

interface Props {
    contacts: Contact[]; // Still accept initial props
}

function SubmitButton() {
    const { pending } = useFormStatus();

    return (
        <button
            type="submit"
            disabled={pending}
            className={cn(
                "group mt-8 flex w-full items-center justify-center gap-2 rounded-xl bg-indigo-500 hover:bg-indigo-400 py-4 font-bold text-white-foreground shadow-xl transition-all active:scale-95 disabled:opacity-70 disabled:active:scale-100",
                pending && "cursor-not-allowed opacity-80"
            )}
        >
            {pending ? (
                <span className="animate-pulse">Envoi en cours...</span>
            ) : (
                <>
                    <span>Confirmer l'envoi</span>
                    <Send className="h-4 w-4 transition-transform group-hover:translate-x-1" />
                </>
            )}
        </button>
    );
}

export function TransferForm({ contacts: initialContacts }: Props) {
    const searchParams = useSearchParams();
    const initialRecipient = searchParams.get("to") || "";

    // État initial pour l'action du form
    const initialState = {
        success: false,
        message: "",
    };

    // Utiliser useActionState au lieu de useFormState
    // @ts-ignore
    const [state, formAction] = useActionState(createTransferAction, initialState);

    const [contacts, setContacts] = useState<Contact[]>(initialContacts);
    const [amount, setAmount] = useState("");
    const [recipient, setRecipient] = useState(initialRecipient);
    const [isLoading, setIsLoading] = useState(false);
    const [errorDismissed, setErrorDismissed] = useState(false); // Moved state up

    // Fetch contacts on mount if empty (Client-Side Fallback)
    useEffect(() => {
        const fetchContacts = async () => {
            if (contacts.length === 0) {
                setIsLoading(true);
                try {
                    const data = await getContactsAction();
                    if (data) setContacts(data);
                } catch (error) {
                    console.error("Failed to fetch contacts client-side", error);
                } finally {
                    setIsLoading(false);
                }
            }
        };
        fetchContacts();
    }, [contacts.length]);

    // Filtrer les contacts valides (ceux avec email ou iban)
    const validContacts = contacts.filter(c => c.email || c.iban);

    // Auto-select contact logic if `initialRecipient` matches a contact ID or email
    useEffect(() => {
        if (initialRecipient && contacts.length > 0) {
            const matched = contacts.find(c => c.contact_id === initialRecipient || c.email === initialRecipient);
            if (matched) {
                setRecipient(matched.email || matched.iban || "");
            } else if (initialRecipient.includes("@") || initialRecipient.startsWith("FR")) {
                // Even if not matched, if param looks like email/iban, set it
                setRecipient(initialRecipient);
            }
        }
    }, [initialRecipient, contacts]);

    // Réinitialiser l'état dismissed lors de la soumission du form
    useEffect(() => {
        if (state?.message) {
            setErrorDismissed(false); // Nouveau message d'erreur, afficher l'écran de blocage
        }
    }, [state]);

    const handleContactClick = (contact: Contact) => {
        setRecipient(contact.email || contact.iban || "");
    };

    // Si nous avons une erreur serveur fraîche et que nous n'avons pas encore laissé de message d'erreur, afficher l'écran de blocage
    if (state?.message && !state.success && !errorDismissed) {
        return (
            <div className="flex flex-1 flex-col items-center justify-center p-6 text-center animate-in zoom-in-95 duration-300">
                <div className="mb-6 relative">
                    <div className="absolute inset-0 bg-red-500/10 blur-2xl rounded-full" />
                    <div className="relative h-20 w-20 bg-red-50 dark:bg-red-900/20 rounded-full flex items-center justify-center border-2 border-red-100 dark:border-red-900">
                        <ShieldCheck className="h-10 w-10 text-red-500" />
                    </div>
                </div>

                <h2 className="text-xl font-bold text-red-600 dark:text-red-500 mb-2">
                    Transaction Refusée
                </h2>

                <p className="text-muted-foreground max-w-xs mb-8">
                    {state.message}
                </p>

                <button
                    onClick={() => setErrorDismissed(true)}
                    className="w-full max-w-xs py-3 px-4 rounded-xl bg-slate-100 dark:bg-slate-800 text-foreground font-medium hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
                >
                    Modifier la transaction
                </button>
            </div>
        );
    }

    return (
        <form action={formAction} className="relative flex flex-1 flex-col h-full">
            <TransactionLoader />
            {/* ... Form Content ... */}
            <div className="space-y-4 py-4">
                <label className="text-sm font-medium text-muted-foreground ml-1">Pour qui ?</label>

                {/* Liste d'accès rapide */}
                {isLoading ? (
                    <div className="flex gap-3 overflow-x-auto pt-1.5 pb-2 scrollbar-hide opacity-50">
                        {[1, 2, 3].map(i => (
                            <div key={i} className="h-10 w-24 bg-slate-100 rounded-full animate-pulse" />
                        ))}
                    </div>
                ) : validContacts.length > 0 ? (
                    <div className="flex gap-3 overflow-x-auto pt-1.5 pb-2 scrollbar-hide">
                        {validContacts.map((c) => (
                            <div
                                key={c.contact_id}
                                onClick={() => handleContactClick(c)}
                                className={cn(
                                    "flex flex-shrink-0 items-center gap-2 rounded-full border bg-white p-1 pr-4 shadow-sm cursor-pointer transition-all dark:bg-slate-900 dark:border-slate-800",
                                    (recipient === c.email || recipient === c.iban)
                                        ? "border-indigo-600 ring-2 ring-indigo-100 dark:ring-indigo-900"
                                        : "border-slate-200 hover:border-indigo-300"
                                )}
                            >
                                <div className={cn(
                                    "h-8 w-8 rounded-full flex items-center justify-center text-xs font-bold",
                                    c.is_internal ? "bg-indigo-100 text-indigo-600" : "bg-slate-100 text-slate-600"
                                )}>
                                    {c.initials}
                                </div>
                                <span className="text-sm font-medium">{c.name}</span>
                            </div>
                        ))}
                    </div>
                ) : (
                    <p className="text-xs text-muted-foreground italic ml-1">Aucun contact enregistré.</p>
                )}

                <div className="relative">
                    <input
                        required
                        name="recipient"
                        type="text"
                        placeholder="Email ou ID utilisateur..."
                        value={recipient}
                        onChange={(e) => setRecipient(e.target.value)}
                        className="w-full rounded-xl border-0 bg-slate-100 px-4 py-4 text-base outline-none ring-1 ring-transparent focus:bg-white focus:ring-primary/20 transition-all dark:bg-slate-800 dark:focus:bg-slate-900 text-slate-900 dark:text-white placeholder:text-slate-400"
                    />
                    {/* Indicateur de statutà l'intérieur du champ */}
                    {recipient && (
                        <div className="absolute right-3 top-1/2 -translate-y-1/2">
                            {contacts.find(c => c.email === recipient) ? (
                                <span className="text-[10px] bg-green-100 text-green-600 px-2 py-1 rounded-full font-bold">Contact</span>
                            ) : (
                                null
                            )}
                        </div>
                    )}
                </div>
            </div>

            {/* Champ Commentaire (Optionnel) */}
            <div className="space-y-2 flex flex-col gap-0.5">
                <label htmlFor="comment" className="text-sm font-medium text-muted-foreground ml-1">Commentaire (optionnel)</label>
                <textarea
                    name="comment"
                    id="comment"
                    rows={2}
                    placeholder="Ajoutez une note à cette transaction..."
                    className="w-full rounded-xl border-0 bg-slate-100 px-4 py-3 text-sm outline-none ring-1 ring-transparent focus:bg-white focus:ring-primary/20 transition-all dark:bg-slate-800 dark:focus:bg-slate-900 text-slate-900 dark:text-white placeholder:text-slate-400 resize-none"
                />
            </div>

            {/* Champ Montant (Centré verticalement) */}
            <div className="flex-1 flex flex-col items-center justify-center gap-4 min-h-[200px]">
                <label htmlFor="amount" className="text-sm font-medium text-muted-foreground uppercase tracking-widest">
                    Montant à envoyer
                </label>
                <div className="relative flex items-center justify-center w-full">
                    <input
                        required
                        name="amount"
                        id="amount"
                        type="text"
                        inputMode="decimal"
                        placeholder="0"
                        value={amount}
                        onChange={(e) => {
                            const val = e.target.value.replace(',', '.'); // Permettre la virgule comme séparateur décimal
                            if (val === '' || /^\d*\.?\d{0,2}$/.test(val)) {
                                setAmount(val);
                            }
                        }}
                        className="w-full text-center bg-transparent text-6xl md:text-8xl font-black tracking-tighter outline-none placeholder:text-slate-100 dark:placeholder:text-slate-800 text-slate-900 dark:text-white transition-all scale-100 focus:scale-105"
                        style={{ maxWidth: '400px' }}
                    />
                    <span className="text-5xl font-medium text-slate-400 absolute right-[10%] top-6 pointer-events-none">PYC</span>
                </div>
            </div>

            {/* Bas des actions */}
            <div className="mt-auto pb-4 space-y-4">

                {/* Affichage du message d'erreur */}
                {state?.message && !state.success && (
                    <div className="bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 p-3 rounded-xl flex items-center gap-2 text-sm font-medium animate-in fade-in slide-in-from-bottom-2 border border-red-100 dark:border-red-900">
                        <div className="h-5 w-5 rounded-full bg-red-100 dark:bg-red-900 flex items-center justify-center shrink-0 font-bold">!</div>
                        {state.message}
                    </div>
                )}

                <div className="rounded-xl bg-slate-50 p-4 text-center text-xs text-muted-foreground dark:bg-slate-900">
                    Frais de transaction : <span className="font-bold text-foreground">Gratuit</span>
                </div>
                <SubmitButton />
            </div>
        </form>
    );
}

"use client";

import { useState, useEffect } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { mockContacts } from '@/lib/mock-data';
import Button from '@/components/ui/Button';
import Card from '@/components/ui/Card';
import { LockClosedIcon, CheckCircleIcon, LightBulbIcon } from '@heroicons/react/24/outline';

export default function VerifyPage() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const amount = searchParams.get('amount');
  const contactId = searchParams.get('contact');
  const [timeRemaining, setTimeRemaining] = useState(45); // secondes
  const [isVerifying, setIsVerifying] = useState(true);
  
  const contact = contactId ? mockContacts.find(c => c.id === contactId) : null;
  
  useEffect(() => {
    if (!isVerifying) return;
    
    const timer = setInterval(() => {
      setTimeRemaining((prev) => {
        if (prev <= 1) {
          setIsVerifying(false);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
    
    return () => clearInterval(timer);
  }, [isVerifying]);
  
  const handleConfirm = async () => {
    // Simuler la confirmation et la validation
    await new Promise(resolve => setTimeout(resolve, 1000));
    router.push(`/?status=validated&amount=${amount}&contact=${contactId}`);
  };
  
  const handleHelp = () => {
    // Simuler l'ouverture du support
    alert('Support: contactez-nous à support@sentinelle.app');
  };
  
  return (
    <div className="min-h-screen pb-20 bg-gradient-to-b from-orange-50 via-white to-blue-50">
      <main className="px-4 py-8 space-y-6">
        {/* Main Message */}
        <div className="text-center py-8">
          <div className="w-24 h-24 mx-auto mb-6 bg-gradient-to-br from-orange-100 to-blue-100 rounded-full flex items-center justify-center">
            <LockClosedIcon className="w-12 h-12 text-orange-600" />
          </div>
          <h2 className="text-2xl font-bold text-gray-900 mb-3">
            Vérification en cours
          </h2>
          <p className="text-lg text-gray-600 max-w-sm mx-auto">
            Nous vérifions cette transaction pour garantir la sécurité de votre compte.
          </p>
        </div>
        
        {/* Transaction Details */}
        <Card className="space-y-4">
          <div className="flex items-center gap-3 pb-4 border-b border-gray-100">
            <div className="w-12 h-12 rounded-full bg-gradient-to-br from-orange-400 to-blue-400 flex items-center justify-center text-white font-semibold">
              {contact?.name.charAt(0) || '?'}
            </div>
            <div className="flex-1">
              <div className="text-sm text-gray-500">Destinataire</div>
              <div className="font-semibold text-gray-900">{contact?.name || 'Contact'}</div>
            </div>
          </div>
          
          <div>
            <div className="text-sm text-gray-500 mb-1">Montant</div>
            <div className="text-2xl font-bold text-gray-900">{amount} €</div>
          </div>
        </Card>
        
        {/* Progress Indicator */}
        {isVerifying && (
          <Card className="bg-gradient-to-r from-orange-50 to-blue-50 border-orange-200">
            <div className="flex items-center gap-3 mb-3">
              <div className="w-8 h-8 border-4 border-orange-200 border-t-orange-500 rounded-full animate-spin" />
              <div className="flex-1">
                <div className="font-semibold text-gray-900 text-sm">Analyse par IA en cours...</div>
                <div className="text-xs text-gray-600">
                  Temps estimé : moins d'une minute
                </div>
              </div>
            </div>
            <div className="w-full bg-orange-200 rounded-full h-2 overflow-hidden">
              <div
                className="bg-gradient-to-r from-orange-500 to-blue-500 h-full transition-all duration-1000 ease-linear"
                style={{ width: `${((45 - timeRemaining) / 45) * 100}%` }}
              />
            </div>
          </Card>
        )}
        
        {/* Success State */}
        {!isVerifying && (
          <Card className="bg-green-50 border-green-200">
            <div className="flex items-center gap-3">
              <CheckCircleIcon className="w-8 h-8 text-green-600 flex-shrink-0" />
              <div>
                <div className="font-semibold text-gray-900">Transaction validée</div>
                <div className="text-sm text-gray-600">
                  Votre paiement a été approuvé et traité avec succès.
                </div>
              </div>
            </div>
          </Card>
        )}
        
        {/* Actions */}
        <div className="space-y-3 pt-4">
          {isVerifying ? (
            <>
              <Button
                variant="primary"
                size="lg"
                className="w-full"
                onClick={handleConfirm}
              >
                Je confirme cette transaction
              </Button>
              <Button
                variant="outline"
                size="md"
                className="w-full"
                onClick={handleHelp}
              >
                Demander de l'aide
              </Button>
            </>
          ) : (
            <Button
              variant="primary"
              size="lg"
              className="w-full"
              onClick={() => router.push('/')}
            >
              Retour à l'accueil
            </Button>
          )}
        </div>
        
        {/* Reassurance Message */}
        <Card className="bg-gray-50">
          <div className="flex items-start gap-3">
            <LightBulbIcon className="w-6 h-6 text-yellow-500 flex-shrink-0 mt-0.5" />
            <div className="text-sm text-gray-600">
              <p className="font-medium text-gray-900 mb-1">Pourquoi cette vérification ?</p>
              <p>
                Notre système de sécurité détecte automatiquement les transactions inhabituelles pour protéger votre compte. C'est normal et cela ne prend que quelques secondes.
              </p>
            </div>
          </div>
        </Card>
      </main>
    </div>
  );
}

'use client';

import { useEffect } from 'react';
import Badge from './ui/Badge';
import { CheckCircleIcon, ExclamationTriangleIcon, XCircleIcon, InformationCircleIcon } from '@heroicons/react/24/outline';

interface NotificationProps {
  message: string;
  type?: 'success' | 'warning' | 'error' | 'info';
  onClose: () => void;
  duration?: number;
}

export default function Notification({
  message,
  type = 'info',
  onClose,
  duration = 5000,
}: NotificationProps) {
  useEffect(() => {
    const timer = setTimeout(onClose, duration);
    return () => clearTimeout(timer);
  }, [duration, onClose]);
  
  const icons = {
    success: CheckCircleIcon,
    warning: ExclamationTriangleIcon,
    error: XCircleIcon,
    info: InformationCircleIcon,
  };
  
  const bgColors = {
    success: 'bg-green-50 border-green-200',
    warning: 'bg-yellow-50 border-yellow-200',
    error: 'bg-red-50 border-red-200',
    info: 'bg-blue-50 border-blue-200',
  };
  
  const IconComponent = icons[type];
  
  return (
    <div className={`fixed top-4 left-4 right-4 max-w-md mx-auto z-50 animate-slide-down`}>
      <div className={`${bgColors[type]} border rounded-xl p-4 shadow-lg flex items-start gap-3`}>
        <IconComponent className={`w-6 h-6 flex-shrink-0 ${
          type === 'success' ? 'text-green-600' :
          type === 'warning' ? 'text-yellow-600' :
          type === 'error' ? 'text-red-600' :
          'text-blue-600'
        }`} />
        <div className="flex-1">
          <p className="text-sm font-medium text-gray-900">{message}</p>
        </div>
        <button
          onClick={onClose}
          className="text-gray-400 hover:text-gray-600 flex-shrink-0"
        >
          <XCircleIcon className="w-5 h-5" />
        </button>
      </div>
    </div>
  );
}

"use client";

import { useState, useMemo } from 'react';
import { TransactionItem } from "@/components/transactions/transaction-item";
import { Transaction, TransactionStatus } from "@/types/transaction";
import { Search, ArrowDownUp, ArrowUpRight, ArrowDownLeft, MoreHorizontal } from "lucide-react";
import { cn } from "@/lib/utils";
import { GlassCard } from "@/components/ui/glass-card";

interface ActivityListProps {
    initialTransactions: Transaction[];
}

export function ActivityList({ initialTransactions }: ActivityListProps) {
    const [searchTerm, setSearchTerm] = useState("");
    const [filter, setFilter] = useState<'ALL' | 'IN' | 'OUT'>('ALL');

    // Filtering Logic
    const filteredTransactions = useMemo(() => {
        return initialTransactions.filter(t => {
            const matchesSearch = t.recipient.toLowerCase().includes(searchTerm.toLowerCase());

            let matchesFilter = true;
            if (filter === 'OUT') {
                matchesFilter = t.direction === 'OUTGOING';
            } else if (filter === 'IN') {
                matchesFilter = t.direction === 'INCOMING';
            }

            return matchesSearch && matchesFilter;
        });
    }, [searchTerm, filter, initialTransactions]);

    // Grouping Logic
    const groupedTransactions = useMemo(() => {
        const groups: Record<string, Transaction[]> = {};

        filteredTransactions.forEach(t => {
            const date = new Date(t.date);
            const today = new Date();
            const yesterday = new Date(today);
            yesterday.setDate(yesterday.getDate() - 1);

            let key = date.toLocaleDateString('fr-FR', { day: 'numeric', month: 'long' });

            if (date.toDateString() === today.toDateString()) key = "Aujourd'hui";
            if (date.toDateString() === yesterday.toDateString()) key = "Hier";

            if (!groups[key]) groups[key] = [];
            groups[key].push(t);
        });

        return groups;
    }, [filteredTransactions]);

    return (
        <div className="space-y-6">
            {/* Controls */}
            <div className="sticky top-20 z-30 space-y-4">
                {/* Search */}
                <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <input
                        type="text"
                        placeholder="Rechercher une transaction..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-3 rounded-xl border-none bg-white dark:bg-slate-900 shadow-sm ring-1 ring-slate-200 dark:ring-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                    />
                </div>

                {/* Filters */}
                <div className="flex p-1 bg-slate-100 dark:bg-slate-900 rounded-xl">
                    {[
                        { key: 'ALL', label: 'Tout', icon: ArrowDownUp },
                        { key: 'OUT', label: 'Dépenses', icon: ArrowUpRight },
                        { key: 'IN', label: 'Entrées', icon: ArrowDownLeft },
                    ].map(tab => (
                        <button
                            key={tab.key}
                            onClick={() => setFilter(tab.key as any)}
                            className={cn(
                                "flex-1 flex items-center justify-center gap-2 py-2 text-sm font-medium rounded-lg transition-all",
                                filter === tab.key
                                    ? "bg-white dark:bg-slate-800 text-indigo-600 shadow-sm"
                                    : "text-muted-foreground hover:text-foreground"
                            )}
                        >
                            <tab.icon className="h-4 w-4" />
                            {tab.label}
                        </button>
                    ))}
                </div>
            </div>

            {/* Grouped List */}
            <div className="space-y-6 pb-20">
                {Object.entries(groupedTransactions).map(([date, txs]) => (
                    <div key={date} className="space-y-3">
                        <h3 className="text-sm font-semibold text-muted-foreground sticky top-[160px] bg-slate-50/80 dark:bg-[#050505]/80 backdrop-blur-sm py-2 px-1 z-20">
                            {date}
                        </h3>
                        <GlassCard className="p-1 overflow-hidden">
                            <div className="divide-y divide-slate-100 dark:divide-slate-800/50">
                                {txs.map((t) => (
                                    <div key={t.id} className="p-2 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors rounded-lg">
                                        <TransactionItem transaction={t} />
                                    </div>
                                ))}
                            </div>
                        </GlassCard>
                    </div>
                ))}

                {Object.keys(groupedTransactions).length === 0 && (
                    <div className="text-center py-12 text-muted-foreground">
                        <div className="h-16 w-16 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center mx-auto mb-4">
                            <MoreHorizontal className="h-8 w-8 text-slate-300 dark:text-slate-600" />
                        </div>
                        <p>Aucune transaction trouvée</p>
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import { useState, useRef, useEffect } from "react";
import Link from "next/link";
